    fn push_style_name_text(&mut self, text: &str, offset: usize) -> Result<(), ParseError> {
        self.count_skipped_destination_bytes(text.len(), offset)?;
        if self.state.style_index.is_none() {
            return Ok(());
        }
        if self.state.style_name_terminated {
            return Ok(());
        }
        let Some(style_name) = text.split(';').next() else {
            return Ok(());
        };
        let new_len = self
            .state
            .style_name_text
            .chars()
            .count()
            .checked_add(style_name.chars().count())
            .ok_or(ParseError::OutputTextTooLarge(offset))?;
        if new_len > self.limits().max_text_run_len {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "style name".to_string(),
                offset,
            });
        }
        self.state.style_name_text.push_str(style_name);
        if text.contains(';') {
            self.state.style_name_terminated = true;
        }
        Ok(())
    }

    fn push_style_name_unicode(&mut self, value: i32, offset: usize) -> Result<(), ParseError> {
        if let Some(ch) =
            take_rtf_unicode_char(&mut self.state.pending_unicode_high_surrogate, value)
        {
            self.push_style_name_text(&ch.to_string(), offset)?;
        }
        self.state.skip_bytes = self.state.unicode_skip;
        Ok(())
    }

    fn start_bookmark_capture(
        &mut self,
        name: String,
        offset: usize,
    ) -> Result<Option<usize>, ParseError> {
        let Some(name) = clean_bookmark_name(name) else {
            return Ok(None);
        };
        if let Some(bookmark) = self
            .bookmark_captures
            .iter_mut()
            .find(|bookmark| bookmark.name == name)
        {
            bookmark.text.clear();
            bookmark.active = true;
            return Ok(Some(bookmark.id));
        }

        if self.bookmark_state_len() >= self.limits().max_bookmarks {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "bookmarks".to_string(),
                offset,
            });
        }
        let id = self.next_bookmark_marker_id;
        self.next_bookmark_marker_id = self.next_bookmark_marker_id.checked_add(1).ok_or(
            ParseError::ResourceLimitExceeded {
                resource: "bookmarks".to_string(),
                offset,
            },
        )?;
        self.bookmark_captures.push(BookmarkCapture {
            id,
            name,
            text: String::new(),
            active: true,
        });
        Ok(Some(id))
    }

    fn end_bookmark_capture(&mut self, name: String) {
        let Some(name) = clean_bookmark_name(name) else {
            return;
        };
        if let Some(bookmark) = self
            .bookmark_captures
            .iter_mut()
            .find(|bookmark| bookmark.name == name && bookmark.active)
        {
            bookmark.active = false;
        }
    }

    fn capture_bookmark_text(&mut self, text: &str, offset: usize) -> Result<(), ParseError> {
        if is_bookmark_page_marker(text) || text == PASSIVE_ADVANCE_MARKER {
            return Ok(());
        }
        let max_text_run_len = self.limits().max_text_run_len;
        for bookmark in self
            .bookmark_captures
            .iter_mut()
            .filter(|bookmark| bookmark.active)
        {
            let new_len = bookmark
                .text
                .chars()
                .count()
                .checked_add(text.chars().count())
                .ok_or(ParseError::OutputTextTooLarge(offset))?;
            if new_len > max_text_run_len {
                return Err(ParseError::ResourceLimitExceeded {
                    resource: "bookmark text".to_string(),
                    offset,
                });
            }
            bookmark.text.push_str(text);
        }
        Ok(())
    }

    fn replace_last_pending_note_marker_in_bookmarks(&mut self, replacement: &str) {
        for bookmark in self.bookmark_captures.iter_mut().rev() {
            if bookmark.text.contains(PENDING_NOTE_REFERENCE_MARKER) {
                bookmark.text =
                    replace_last_marker(&bookmark.text, PENDING_NOTE_REFERENCE_MARKER, replacement);
                return;
            }
        }
    }

    fn replace_all_pending_note_markers_in_bookmarks(&mut self, replacement: &str) {
        for bookmark in &mut self.bookmark_captures {
            if bookmark.text.contains(PENDING_NOTE_REFERENCE_MARKER) {
                bookmark.text = bookmark
                    .text
                    .replace(PENDING_NOTE_REFERENCE_MARKER, replacement);
            }
        }
    }

    fn bookmark_captured_text(&self, name: &str) -> Option<String> {
        let name = clean_bookmark_name(name.to_string())?;
        self.bookmark_captures
            .iter()
            .find(|bookmark| bookmark.name == name && !bookmark.active && !bookmark.text.is_empty())
            .map(|bookmark| bookmark.text.clone())
    }

    fn bookmark_text(&self, name: &str) -> Option<String> {
        let text = self.bookmark_captured_text(name)?;
        if contains_internal_marker(&text) || text.chars().any(|ch| ch.is_control()) {
            return None;
        }
        Some(text)
    }

    fn ensure_bookmark_marker_id(
        &mut self,
        name: String,
        offset: usize,
    ) -> Result<Option<usize>, ParseError> {
        let Some(name) = clean_bookmark_name(name) else {
            return Ok(None);
        };
        if let Some(bookmark) = self
            .bookmark_captures
            .iter()
            .find(|bookmark| bookmark.name == name)
        {
            return Ok(Some(bookmark.id));
        }
        if self.bookmark_state_len() >= self.limits().max_bookmarks {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "bookmarks".to_string(),
                offset,
            });
        }
        let id = self.next_bookmark_marker_id;
        self.next_bookmark_marker_id = self.next_bookmark_marker_id.checked_add(1).ok_or(
            ParseError::ResourceLimitExceeded {
                resource: "bookmarks".to_string(),
                offset,
            },
        )?;
        self.bookmark_captures.push(BookmarkCapture {
            id,
            name,
            text: String::new(),
            active: false,
        });
        Ok(Some(id))
    }

    fn bookmark_state_len(&self) -> usize {
        self.bookmark_captures
            .len()
            .saturating_add(self.field_bookmark_values.len())
    }

