    fn store_document_property(
        &mut self,
        property: DocumentProperty,
        text: &str,
        offset: usize,
    ) -> Result<(), ParseError> {
        let text = text.trim().to_string();
        if text.is_empty()
            || text.chars().any(|ch| ch.is_control())
            || contains_internal_marker(&text)
        {
            return Ok(());
        }

        if text.chars().count() > self.limits().max_text_run_len {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "document property text".to_string(),
                offset,
            });
        }

        if let Some((_, existing)) = self
            .document_properties
            .iter_mut()
            .find(|(stored_property, _)| *stored_property == property)
        {
            *existing = text;
        } else {
            self.document_properties.push((property, text));
        }
        Ok(())
    }

    fn set_document_timestamp_part(
        &mut self,
        name: &str,
        value: Option<i32>,
        offset: usize,
    ) -> Result<(), ParseError> {
        let Some(value) = value else {
            return Ok(());
        };
        match name {
            "yr" => self.state.metadata_timestamp_value.year = Some(value),
            "mo" => self.state.metadata_timestamp_value.month = Some(value),
            "dy" => self.state.metadata_timestamp_value.day = Some(value),
            "hr" => self.state.metadata_timestamp_value.hour = Some(value),
            "min" => self.state.metadata_timestamp_value.minute = Some(value),
            "sec" => self.state.metadata_timestamp_value.second = Some(value),
            _ => {}
        }
        self.count_skipped_destination_bytes(name.len(), offset)
    }

    fn store_document_timestamp(
        &mut self,
        kind: DocumentTimestampKind,
        timestamp: DocumentTimestamp,
        offset: usize,
    ) -> Result<(), ParseError> {
        let Some(timestamp) = normalize_document_timestamp(timestamp) else {
            return Ok(());
        };
        if let Some((_, existing)) = self
            .document_timestamps
            .iter_mut()
            .find(|(stored_kind, _)| *stored_kind == kind)
        {
            *existing = timestamp;
        } else {
            if self.document_timestamps.len() >= 3 {
                return Err(ParseError::ResourceLimitExceeded {
                    resource: "document timestamps".to_string(),
                    offset,
                });
            }
            self.document_timestamps.push((kind, timestamp));
        }
        Ok(())
    }

    fn set_document_edit_minutes(
        &mut self,
        value: Option<i32>,
        offset: usize,
    ) -> Result<(), ParseError> {
        self.count_skipped_destination_bytes("edmins".len(), offset)?;
        let Some(value) = value else {
            return Ok(());
        };
        if value < 0 {
            return Ok(());
        }
        let max = self.limits().max_output_text_chars.min(i32::MAX as usize) as i32;
        if value > max {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "document edit minutes".to_string(),
                offset,
            });
        }
        self.document_edit_minutes = Some(value);
        Ok(())
    }

    fn set_document_revision_number(
        &mut self,
        value: Option<i32>,
        offset: usize,
    ) -> Result<(), ParseError> {
        self.count_skipped_destination_bytes("version".len(), offset)?;
        let Some(value) = value else {
            return Ok(());
        };
        if value < 0 {
            return Ok(());
        }
        let max = self.limits().max_output_text_chars.min(i32::MAX as usize) as i32;
        if value > max {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "document revision number".to_string(),
                offset,
            });
        }
        self.document_revision_number = Some(value);
        Ok(())
    }

    fn push_user_property_text(&mut self, text: &str, offset: usize) -> Result<(), ParseError> {
        self.count_skipped_destination_bytes(text.len(), offset)?;
        if contains_internal_marker(text) {
            return Ok(());
        }

        let safe_text = text
            .chars()
            .filter(|ch| !ch.is_control())
            .collect::<String>();
        let new_len = self
            .state
            .user_property_capture_text
            .chars()
            .count()
            .checked_add(safe_text.chars().count())
            .ok_or(ParseError::OutputTextTooLarge(offset))?;
        if new_len > self.limits().max_text_run_len {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "custom document property text".to_string(),
                offset,
            });
        }
        self.state.user_property_capture_text.push_str(&safe_text);
        Ok(())
    }

    fn push_user_property_unicode(&mut self, value: i32, offset: usize) -> Result<(), ParseError> {
        if let Some(ch) =
            take_rtf_unicode_char(&mut self.state.pending_unicode_high_surrogate, value)
        {
            self.push_user_property_text(&ch.to_string(), offset)?;
        } else {
            self.count_skipped_destination_bytes(1, offset)?;
        }
        self.state.skip_bytes = self.state.unicode_skip;
        Ok(())
    }

    fn push_document_variable_text(&mut self, text: &str, offset: usize) -> Result<(), ParseError> {
        self.count_skipped_destination_bytes(text.len(), offset)?;
        if contains_internal_marker(text) {
            return Ok(());
        }

        let safe_text = text
            .chars()
            .filter(|ch| !ch.is_control())
            .collect::<String>();
        let new_len = self
            .state
            .document_variable_capture_text
            .chars()
            .count()
            .checked_add(safe_text.chars().count())
            .ok_or(ParseError::OutputTextTooLarge(offset))?;
        if new_len > self.limits().max_text_run_len {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "document variable text".to_string(),
                offset,
            });
        }
        self.state
            .document_variable_capture_text
            .push_str(&safe_text);
        Ok(())
    }

    fn push_document_variable_unicode(
        &mut self,
        value: i32,
        offset: usize,
    ) -> Result<(), ParseError> {
        if let Some(ch) =
            take_rtf_unicode_char(&mut self.state.pending_unicode_high_surrogate, value)
        {
            self.push_document_variable_text(&ch.to_string(), offset)?;
        } else {
            self.count_skipped_destination_bytes(1, offset)?;
        }
        self.state.skip_bytes = self.state.unicode_skip;
        Ok(())
    }

    fn store_document_variable(
        &mut self,
        name: &str,
        text: &str,
        offset: usize,
    ) -> Result<(), ParseError> {
        let Some(text) = clean_document_property_text(text, offset, self.limits())? else {
            return Ok(());
        };

        if let Some((_, existing)) = self
            .document_variables
            .iter_mut()
            .find(|(stored_name, _)| stored_name.eq_ignore_ascii_case(name))
        {
            *existing = text;
        } else {
            if self.document_property_state_len() >= self.limits().max_document_properties {
                return Err(ParseError::ResourceLimitExceeded {
                    resource: "document variables".to_string(),
                    offset,
                });
            }
            self.document_variables.push((name.to_string(), text));
        }
        Ok(())
    }

    fn store_custom_document_property(
        &mut self,
        name: &str,
        text: &str,
        offset: usize,
    ) -> Result<(), ParseError> {
        let Some(text) = clean_document_property_text(text, offset, self.limits())? else {
            return Ok(());
        };

        if let Some((_, existing)) = self
            .custom_document_properties
            .iter_mut()
            .find(|(stored_name, _)| stored_name.eq_ignore_ascii_case(name))
        {
            *existing = text;
        } else {
            if self.document_property_state_len() >= self.limits().max_document_properties {
                return Err(ParseError::ResourceLimitExceeded {
                    resource: "custom document properties".to_string(),
                    offset,
                });
            }
            self.custom_document_properties
                .push((name.to_string(), text));
        }
        Ok(())
    }

    fn document_property_state_len(&self) -> usize {
        self.document_variables
            .len()
            .saturating_add(self.custom_document_properties.len())
    }

    fn push_passive_field_result(
        &mut self,
        result: PassiveFieldResult,
        instruction: &str,
        offset: usize,
    ) -> Result<(), ParseError> {
        let previous_shading = self.state.character.form_field_shading;
        self.state.character.form_field_shading = self.form_field_shading && result.form_field;
        let previous_font = self.state.character.font_index;
        let previous_font_size = self.state.character.font_size_half_points;

        if let Some(font_name) = result.font_name.as_deref()
            && let Some(font_index) = self.ensure_passive_result_font(font_name, offset)?
        {
            self.state.character.font_index = font_index;
        }
        if let Some(font_size_half_points) = result.font_size_half_points {
            self.state.character.font_size_half_points =
                self.clamp_font_size(font_size_half_points, offset);
        }

        let result = if field_instruction_name(instruction) == Some("EQ") {
            if let Some(segments) = passive_eq_field_segments(instruction).filter(|segments| {
                segments
                    .iter()
                    .map(|segment| segment.text.as_str())
                    .collect::<String>()
                    == result.text
            }) {
                self.push_passive_field_segments(&segments, offset)
            } else {
                self.push_text(&result.text, offset)
            }
        } else {
            self.push_text(&result.text, offset)
        };
        self.state.character.font_size_half_points = previous_font_size;
        self.state.character.font_index = previous_font;
        self.state.character.form_field_shading = previous_shading;
        result
    }

    fn push_passive_field_segments(
        &mut self,
        segments: &[PassiveFieldSegment],
        offset: usize,
    ) -> Result<(), ParseError> {
        let previous_baseline_shift = self.state.character.baseline_shift_half_points;
        let previous_font_size_scale = self.state.character.font_size_scale_percent;
        let previous_overline = self.state.character.overline;
        let mut result = Ok(());

        for segment in segments {
            self.state.character.baseline_shift_half_points = segment
                .baseline_shift_half_points
                .unwrap_or(previous_baseline_shift);
            self.state.character.font_size_scale_percent = segment
                .font_size_scale_percent
                .unwrap_or(previous_font_size_scale);
            self.state.character.overline = previous_overline || segment.overline;
            result = self.push_text(&segment.text, offset);
            if result.is_err() {
                break;
            }
        }

        self.state.character.baseline_shift_half_points = previous_baseline_shift;
        self.state.character.font_size_scale_percent = previous_font_size_scale;
        self.state.character.overline = previous_overline;
        result
    }

    fn handle_resultless_layout_field(
        &mut self,
        name: &str,
        instruction: &str,
        offset: usize,
    ) -> Result<(), ParseError> {
        if name == "ADVANCE" {
            let advance = passive_advance_field_offset_twips(
                instruction,
                self.limits().max_character_spacing_twips,
            );
            if advance.horizontal_twips != 0 || advance.vertical_twips != 0 {
                self.push_passive_advance_marker(
                    advance.horizontal_twips,
                    advance.vertical_twips,
                    offset,
                )?;
            }
            if advance.horizontal_twips != 0 {
                self.diagnostics.push(Diagnostic::warning(
                    "layout field ADVANCE interpreted as bounded passive horizontal cursor advance",
                    Some(offset),
                ));
            }
            if advance.vertical_twips != 0 {
                self.diagnostics.push(Diagnostic::warning(
                    "layout field ADVANCE interpreted as bounded passive vertical cursor advance",
                    Some(offset),
                ));
            }
            if advance.horizontal_twips == 0 && advance.vertical_twips == 0 {
                self.diagnostics.push(Diagnostic::warning(
                    "layout field ADVANCE stripped without applying cursor positioning",
                    Some(offset),
                ));
            }
            return Ok(());
        }

        self.diagnostics.push(Diagnostic::warning(
            format!("layout field {name} stripped without applying cursor positioning"),
            Some(offset),
        ));
        Ok(())
    }

    fn push_passive_advance_marker(
        &mut self,
        horizontal_twips: i32,
        vertical_twips: i32,
        offset: usize,
    ) -> Result<(), ParseError> {
        let previous_spacing = self.state.character.character_spacing_twips;
        let previous_baseline_shift = self.state.character.baseline_shift_half_points;
        self.state.character.character_spacing_twips = horizontal_twips;
        self.state.character.baseline_shift_half_points = vertical_twips / 10;
        let result = self.push_text(PASSIVE_ADVANCE_MARKER, offset);
        self.state.character.character_spacing_twips = previous_spacing;
        self.state.character.baseline_shift_half_points = previous_baseline_shift;
        result
    }

    fn passive_field_result_for_instruction(
        &mut self,
        instruction: &str,
        form_checkbox_checked: Option<bool>,
        form_default_text: &str,
        form_dropdown_entries: &[String],
        form_dropdown_selected_index: Option<i32>,
        offset: usize,
    ) -> Result<Option<PassiveFieldResult>, ParseError> {
        let result = if field_instruction_name(instruction) == Some("SEQ") {
            self.passive_sequence_field_result(instruction, offset)?
        } else if field_instruction_name(instruction).is_some_and(is_auto_number_field) {
            self.passive_auto_number_field_result(offset)?
        } else if field_instruction_name(instruction) == Some("LISTNUM") {
            self.passive_list_number_field_result(instruction, offset)?
        } else if field_instruction_name(instruction) == Some("SET") {
            self.passive_set_field_result(instruction, offset)?
        } else if field_instruction_name(instruction) == Some("REF") {
            self.passive_ref_field_result(instruction)
        } else if field_instruction_name(instruction) == Some("NOTEREF") {
            self.passive_noteref_field_result(instruction)
        } else if field_instruction_name(instruction) == Some("PAGEREF") {
            self.passive_page_ref_field_result(instruction, offset)?
        } else if field_instruction_name(instruction) == Some("STYLEREF") {
            self.passive_style_ref_field_result(instruction)
        } else if field_instruction_name(instruction) == Some("DOCPROPERTY") {
            self.passive_doc_property_field_result(instruction)
        } else if field_instruction_name(instruction) == Some("DOCVARIABLE") {
            self.passive_doc_variable_field_result(instruction)
        } else if field_instruction_name(instruction) == Some("INFO") {
            self.passive_info_field_result(instruction)
        } else if let Some(property) =
            field_instruction_name(instruction).and_then(document_shortcut_property_field_name)
        {
            self.passive_builtin_document_property_field_result(property)
        } else if let Some(kind) =
            field_instruction_name(instruction).and_then(document_timestamp_field_name)
        {
            self.passive_document_timestamp_field_result(kind, instruction)
        } else if field_instruction_name(instruction) == Some("EDITTIME") {
            self.passive_edit_time_field_result()
        } else if field_instruction_name(instruction) == Some("REVNUM") {
            self.passive_revision_number_field_result()
        } else {
            passive_field_result(
                instruction,
                form_checkbox_checked,
                form_default_text,
                form_dropdown_entries,
                form_dropdown_selected_index,
            )
        };

        Ok(result.and_then(|result| apply_field_format_switches(instruction, result)))
    }

    fn passive_doc_property_field_result(&self, instruction: &str) -> Option<PassiveFieldResult> {
        let name = field_first_argument(instruction)?;
        let text = if let Some(property) = document_property_field_name(&name) {
            self.document_property_text(property)?
        } else {
            self.custom_document_properties
                .iter()
                .find_map(|(stored_name, text)| {
                    stored_name.eq_ignore_ascii_case(&name).then(|| text)
                })?
        };
        Some(PassiveFieldResult {
            text: text.clone(),
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        })
    }

    fn passive_doc_variable_field_result(&self, instruction: &str) -> Option<PassiveFieldResult> {
        let name = field_first_argument(instruction)?;
        let text = self
            .document_variables
            .iter()
            .find_map(|(stored_name, text)| {
                stored_name.eq_ignore_ascii_case(&name).then(|| text)
            })?;
        Some(PassiveFieldResult {
            text: text.clone(),
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        })
    }

    fn passive_info_field_result(&self, instruction: &str) -> Option<PassiveFieldResult> {
        let name = field_first_argument(instruction)?;
        let property = document_property_field_name(&name)?;
        Some(PassiveFieldResult {
            text: self.document_property_text(property)?.clone(),
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        })
    }

    fn passive_builtin_document_property_field_result(
        &self,
        property: DocumentProperty,
    ) -> Option<PassiveFieldResult> {
        Some(PassiveFieldResult {
            text: self.document_property_text(property)?.clone(),
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        })
    }

    fn document_property_text(&self, property: DocumentProperty) -> Option<&String> {
        self.document_properties
            .iter()
            .find_map(|(stored_property, text)| (*stored_property == property).then(|| text))
    }

    fn passive_document_timestamp_field_result(
        &self,
        kind: DocumentTimestampKind,
        instruction: &str,
    ) -> Option<PassiveFieldResult> {
        let timestamp = self
            .document_timestamps
            .iter()
            .find_map(|(stored_kind, timestamp)| (*stored_kind == kind).then_some(timestamp))?;
        let text = if let Some(picture) = field_date_picture_switch(instruction)? {
            apply_field_date_picture(timestamp, &picture)?
        } else {
            format_default_document_timestamp(timestamp)
        };
        Some(PassiveFieldResult {
            text,
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        })
    }

    fn passive_edit_time_field_result(&self) -> Option<PassiveFieldResult> {
        Some(PassiveFieldResult {
            text: self.document_edit_minutes?.to_string(),
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        })
    }

    fn passive_revision_number_field_result(&self) -> Option<PassiveFieldResult> {
        Some(PassiveFieldResult {
            text: self.document_revision_number?.to_string(),
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        })
    }

    fn passive_set_field_result(
        &mut self,
        instruction: &str,
        offset: usize,
    ) -> Result<Option<PassiveFieldResult>, ParseError> {
        if let Some((name, value)) = field_set_instruction(instruction, offset, self.limits())? {
            self.set_field_bookmark_value(name, value, offset)?;
        }
        Ok(Some(PassiveFieldResult {
            text: String::new(),
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        }))
    }

    fn passive_sequence_field_result(
        &mut self,
        instruction: &str,
        offset: usize,
    ) -> Result<Option<PassiveFieldResult>, ParseError> {
        let Some(sequence) = field_sequence_instruction(instruction) else {
            return Ok(None);
        };

        let max_value = self.limits().max_page_number_start.max(1);
        let value = if let Some(reset_value) = sequence.reset_value {
            if reset_value < 0 || reset_value > max_value {
                return Err(ParseError::ResourceLimitExceeded {
                    resource: "field sequence value".to_string(),
                    offset,
                });
            }
            self.set_sequence_counter(sequence.name, reset_value, offset)?
        } else if sequence.repeat_current {
            let Some(counter) = self
                .field_sequence_counters
                .iter()
                .find(|counter| counter.name == sequence.name)
            else {
                return Ok(None);
            };
            counter.value
        } else {
            self.increment_sequence_counter(sequence.name, max_value, offset)?
        };

        let text = if sequence.hidden {
            String::new()
        } else {
            value.to_string()
        };
        Ok(Some(PassiveFieldResult {
            text,
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        }))
    }

    fn set_sequence_counter(
        &mut self,
        name: String,
        value: i32,
        offset: usize,
    ) -> Result<i32, ParseError> {
        if let Some(counter) = self
            .field_sequence_counters
            .iter_mut()
            .find(|counter| counter.name == name)
        {
            counter.value = value;
            return Ok(value);
        }

        if self.field_counter_state_len() >= self.limits().max_field_counters {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "field sequences".to_string(),
                offset,
            });
        }
        self.field_sequence_counters
            .push(FieldSequenceCounter { name, value });
        Ok(value)
    }

    fn increment_sequence_counter(
        &mut self,
        name: String,
        max_value: i32,
        offset: usize,
    ) -> Result<i32, ParseError> {
        if let Some(counter) = self
            .field_sequence_counters
            .iter_mut()
            .find(|counter| counter.name == name)
        {
            if counter.value >= max_value {
                return Err(ParseError::ResourceLimitExceeded {
                    resource: "field sequence value".to_string(),
                    offset,
                });
            }
            counter.value += 1;
            return Ok(counter.value);
        }

        self.set_sequence_counter(name, 1, offset)
    }

    fn passive_auto_number_field_result(
        &mut self,
        offset: usize,
    ) -> Result<Option<PassiveFieldResult>, ParseError> {
        let max_value = self.limits().max_page_number_start.max(1);
        if self.field_auto_number_counter >= max_value {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "field auto number value".to_string(),
                offset,
            });
        }
        self.field_auto_number_counter += 1;
        Ok(Some(PassiveFieldResult {
            text: self.field_auto_number_counter.to_string(),
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        }))
    }

    fn passive_list_number_field_result(
        &mut self,
        instruction: &str,
        offset: usize,
    ) -> Result<Option<PassiveFieldResult>, ParseError> {
        let Some(list_number) = field_list_number_instruction(instruction) else {
            return Ok(None);
        };

        let max_value = self.limits().max_page_number_start.max(1);
        let key = format!("{}\u{1f}{}", list_number.name, list_number.level);
        let value = if let Some(reset_value) = list_number.reset_value {
            if reset_value < 0 || reset_value > max_value {
                return Err(ParseError::ResourceLimitExceeded {
                    resource: "field list number value".to_string(),
                    offset,
                });
            }
            self.set_list_number_counter(key, reset_value, offset)?
        } else {
            self.increment_list_number_counter(key, max_value, offset)?
        };

        Ok(Some(PassiveFieldResult {
            text: value.to_string(),
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        }))
    }

    fn set_list_number_counter(
        &mut self,
        name: String,
        value: i32,
        offset: usize,
    ) -> Result<i32, ParseError> {
        if let Some(counter) = self
            .field_list_number_counters
            .iter_mut()
            .find(|counter| counter.name == name)
        {
            counter.value = value;
            return Ok(value);
        }

        if self.field_counter_state_len() >= self.limits().max_field_counters {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "field list numbers".to_string(),
                offset,
            });
        }
        self.field_list_number_counters
            .push(FieldSequenceCounter { name, value });
        Ok(value)
    }

    fn increment_list_number_counter(
        &mut self,
        name: String,
        max_value: i32,
        offset: usize,
    ) -> Result<i32, ParseError> {
        if let Some(counter) = self
            .field_list_number_counters
            .iter_mut()
            .find(|counter| counter.name == name)
        {
            if counter.value >= max_value {
                return Err(ParseError::ResourceLimitExceeded {
                    resource: "field list number value".to_string(),
                    offset,
                });
            }
            counter.value += 1;
            return Ok(counter.value);
        }

        self.set_list_number_counter(name, 1, offset)
    }

    fn field_counter_state_len(&self) -> usize {
        self.field_sequence_counters
            .len()
            .saturating_add(self.field_list_number_counters.len())
    }

    fn passive_ref_field_result(&self, instruction: &str) -> Option<PassiveFieldResult> {
        let name = field_first_argument(instruction)?;
        let text = self
            .bookmark_text(&name)
            .or_else(|| self.field_bookmark_value(&name))?;
        Some(PassiveFieldResult {
            text,
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        })
    }

    fn passive_noteref_field_result(&self, instruction: &str) -> Option<PassiveFieldResult> {
        let name = field_first_argument(instruction)?;
        if let Some(text) = self.bookmark_captured_text(&name)
            && let Some(text) = self.passive_footnote_marker_noteref_text(&text, instruction)
        {
            return Some(PassiveFieldResult {
                text,
                font_name: None,
                font_size_half_points: None,
                form_field: false,
            });
        }
        self.passive_ref_field_result(instruction)
    }

    fn passive_footnote_marker_noteref_text(
        &self,
        text: &str,
        instruction: &str,
    ) -> Option<String> {
        if text.chars().any(|ch| ch.is_control()) {
            return None;
        }
        let text = strip_bookmark_page_markers(text)?;
        let note_index = parse_footnote_reference_marker_id(&text)?;
        if note_index > self.document.footnotes.len() {
            return None;
        }
        let sequence = match self.document.footnote_number_restart {
            NoteNumberRestart::Continuous => note_index + 1,
            NoteNumberRestart::EachSection => {
                let section = self
                    .document
                    .footnote_section_indices
                    .get(note_index)
                    .copied()
                    .unwrap_or_else(|| self.current_section_index.max(1));
                let prior_count = self
                    .document
                    .footnote_section_indices
                    .iter()
                    .take(note_index)
                    .filter(|candidate| **candidate == section)
                    .count();
                prior_count + 1
            }
            NoteNumberRestart::EachPage => return None,
        };
        let value = self.document.footnote_number_start + sequence as i32 - 1;
        if field_uses_numeric_formatting(instruction) {
            Some(value.to_string())
        } else {
            Some(format_note_number(
                self.document.footnote_number_start,
                sequence,
                self.document.footnote_number_format,
            ))
        }
    }

    fn field_bookmark_value(&self, name: &str) -> Option<String> {
        let name = clean_bookmark_name(name.to_string())?;
        self.field_bookmark_values
            .iter()
            .rev()
            .find_map(|(stored_name, text)| {
                stored_name
                    .eq_ignore_ascii_case(&name)
                    .then(|| text.clone())
            })
    }

    fn set_field_bookmark_value(
        &mut self,
        name: String,
        value: String,
        offset: usize,
    ) -> Result<(), ParseError> {
        if let Some((_, stored_value)) = self
            .field_bookmark_values
            .iter_mut()
            .find(|(stored_name, _)| stored_name.eq_ignore_ascii_case(&name))
        {
            *stored_value = value;
            return Ok(());
        }

        if self.bookmark_state_len() >= self.limits().max_bookmarks {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "field bookmark values".to_string(),
                offset,
            });
        }
        self.field_bookmark_values.push((name, value));
        Ok(())
    }

    fn passive_page_ref_field_result(
        &mut self,
        instruction: &str,
        offset: usize,
    ) -> Result<Option<PassiveFieldResult>, ParseError> {
        let Some(name) = field_first_argument(instruction) else {
            return Ok(None);
        };
        let Some(id) = self.ensure_bookmark_marker_id(name, offset)? else {
            return Ok(None);
        };
        Ok(Some(PassiveFieldResult {
            text: bookmark_page_ref_marker(id),
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        }))
    }

    fn passive_style_ref_field_result(&self, instruction: &str) -> Option<PassiveFieldResult> {
        let Some(style_index) = self.field_style_ref_index(instruction) else {
            return None;
        };
        let text = self
            .style_reference_texts
            .iter()
            .rev()
            .find_map(|(index, text)| (*index == style_index).then(|| text.clone()))?;
        Some(PassiveFieldResult {
            text,
            font_name: None,
            font_size_half_points: None,
            form_field: false,
        })
    }

    fn field_style_ref_index(&self, instruction: &str) -> Option<i32> {
        let name = field_first_argument(instruction)?;
        let rest = field_rest_after_first_argument(instruction)?;
        if !field_remainder_contains_only_passive_format_switches(rest) {
            return None;
        }
        if let Ok(index) = name.trim().parse::<i32>() {
            return Some(index);
        }
        let name = clean_style_ref_name(&name)?;
        self.styles.iter().find_map(|style| {
            (style.kind == StyleKind::Paragraph
                && style
                    .name
                    .as_deref()
                    .is_some_and(|stored_name| stored_name.eq_ignore_ascii_case(&name)))
            .then_some(style.index)
        })
    }

    fn ensure_passive_result_font(
        &mut self,
        font_name: &str,
        offset: usize,
    ) -> Result<Option<i32>, ParseError> {
        if let Some(font_index) = self
            .document
            .fonts
            .iter()
            .find(|font| font.name.eq_ignore_ascii_case(font_name))
            .map(|font| font.index)
        {
            return Ok(Some(font_index));
        }

        if !is_builtin_passive_result_font(font_name) {
            return Ok(None);
        }

        if self.document.fonts.len() >= self.limits().max_fonts {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "fonts".to_string(),
                offset,
            });
        }

        let next_index = self
            .document
            .fonts
            .iter()
            .map(|font| font.index)
            .max()
            .unwrap_or(-1)
            .checked_add(1)
            .ok_or(ParseError::ResourceLimitExceeded {
                resource: "fonts".to_string(),
                offset,
            })?;
        self.document.fonts.push(FontDef {
            index: next_index,
            name: "ZapfDingbats".to_string(),
            alternate_name: None,
            charset: None,
            code_page: None,
            family: FontFamilyHint::Tech,
            pitch: FontPitch::Default,
        });
        Ok(Some(next_index))
    }

    fn push_list_marker_unicode(&mut self, value: i32, offset: usize) -> Result<(), ParseError> {
        if let Some(ch) =
            take_rtf_unicode_char(&mut self.state.pending_unicode_high_surrogate, value)
        {
            self.push_list_marker_text(&ch.to_string(), offset)?;
        }
        self.state.skip_bytes = self.state.unicode_skip;
        Ok(())
    }

    fn push_unicode(&mut self, value: i32, offset: usize) -> Result<(), ParseError> {
        if let Some(ch) =
            take_rtf_unicode_char(&mut self.state.pending_unicode_high_surrogate, value)
        {
            self.push_text(&ch.to_string(), offset)?;
        }
        self.state.skip_bytes = self.state.unicode_skip;
        Ok(())
    }

    fn finish_paragraph(&mut self, offset: usize) -> Result<(), ParseError> {
        let paragraph_style_index = self.state.paragraph_style_index;
        let mut pending_style_reference_text = None;
        if self.state.destination == Destination::ShapeText {
            self.finish_shape_text_paragraph();
            return Ok(());
        }
        if let Some(row) = self.current_table_row.as_mut() {
            if !row.current_cell_paragraph.runs.is_empty() {
                let paragraph = std::mem::replace(
                    &mut row.current_cell_paragraph,
                    Paragraph {
                        style: self.state.paragraph.clone(),
                        runs: Vec::new(),
                    },
                );
                if paragraph_style_index.is_some() {
                    pending_style_reference_text = paragraph_plain_text(&paragraph);
                }
                row.current_cell_paragraphs.push(paragraph);
                row.cell_open = true;
            }
            if let (Some(index), Some(text)) = (paragraph_style_index, pending_style_reference_text)
            {
                self.store_style_reference_text(index, text, offset)?;
            }
            return Ok(());
        }

        if !self.current_paragraph.runs.is_empty() {
            let paragraph = std::mem::replace(
                &mut self.current_paragraph,
                Paragraph {
                    style: self.state.paragraph.clone(),
                    runs: Vec::new(),
                },
            );
            if let Some(index) = paragraph_style_index {
                if let Some(text) = paragraph_plain_text(&paragraph) {
                    self.store_style_reference_text(index, text, offset)?;
                }
            }
            self.push_document_block(Block::Paragraph(paragraph), offset)?;
        }
        Ok(())
    }

    fn store_style_reference_text(
        &mut self,
        style_index: i32,
        text: String,
        offset: usize,
    ) -> Result<(), ParseError> {
        if text.is_empty()
            || text.chars().count() > self.limits().max_text_run_len
            || text.chars().any(|ch| ch.is_control())
            || contains_internal_marker(&text)
        {
            return Ok(());
        }
        if let Some((_, stored_text)) = self
            .style_reference_texts
            .iter_mut()
            .find(|(index, _)| *index == style_index)
        {
            *stored_text = text;
            return Ok(());
        }
        if self.style_reference_texts.len() >= self.limits().max_style_references {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "style references".to_string(),
                offset,
            });
        }
        self.style_reference_texts.push((style_index, text));
        Ok(())
    }

    fn finish_current_paragraph_for_destination(
        &mut self,
        offset: usize,
    ) -> Result<(), ParseError> {
        let advance_next_style = match self.state.destination {
            Destination::Body => {
                self.finish_paragraph(offset)?;
                true
            }
            destination if is_header_destination(destination) => {
                self.finish_header_paragraph(offset)?;
                true
            }
            destination if is_footer_destination(destination) => {
                self.finish_footer_paragraph(offset)?;
                true
            }
            Destination::Footnote => {
                self.finish_footnote_paragraph(offset)?;
                true
            }
            Destination::Endnote => {
                self.finish_endnote_paragraph(offset)?;
                true
            }
            destination if is_note_separator_destination(destination) => {
                self.finish_note_separator_paragraph(offset)?;
                true
            }
            Destination::ShapeText => {
                self.finish_shape_text_paragraph();
                true
            }
            Destination::ListText => false,
            _ => {
                self.finish_paragraph(offset)?;
                false
            }
        };
        if advance_next_style {
            self.apply_next_style_after_paragraph(offset);
        }
        Ok(())
    }

    fn finish_header_paragraph(&mut self, offset: usize) -> Result<(), ParseError> {
        let destination = self.state.destination;
        let current = match destination {
            Destination::FirstPageHeader => &mut self.current_first_page_header_paragraph,
            Destination::EvenPageHeader => &mut self.current_even_page_header_paragraph,
            _ => &mut self.current_header_paragraph,
        };
        if !current.runs.is_empty() {
            let paragraph = std::mem::replace(
                current,
                Paragraph {
                    style: self.state.paragraph.clone(),
                    runs: Vec::new(),
                },
            );
            self.reserve_header_footer_paragraph_slot(offset)?;
            if self.has_started_visible_body() {
                match destination {
                    Destination::FirstPageHeader => {
                        self.current_section_page.first_page_header.push(paragraph)
                    }
                    Destination::EvenPageHeader => {
                        self.current_section_page.even_page_header.push(paragraph)
                    }
                    _ => self.current_section_page.header.push(paragraph),
                }
                self.upsert_current_section_settings();
            } else {
                match destination {
                    Destination::FirstPageHeader => self.document.first_page_header.push(paragraph),
                    Destination::EvenPageHeader => self.document.even_page_header.push(paragraph),
                    _ => self.document.header.push(paragraph),
                }
            }
        }
        Ok(())
    }

    fn finish_footer_paragraph(&mut self, offset: usize) -> Result<(), ParseError> {
        let destination = self.state.destination;
        let current = match destination {
            Destination::FirstPageFooter => &mut self.current_first_page_footer_paragraph,
            Destination::EvenPageFooter => &mut self.current_even_page_footer_paragraph,
            _ => &mut self.current_footer_paragraph,
        };
        if !current.runs.is_empty() {
            let paragraph = std::mem::replace(
                current,
                Paragraph {
                    style: self.state.paragraph.clone(),
                    runs: Vec::new(),
                },
            );
            self.reserve_header_footer_paragraph_slot(offset)?;
            if self.has_started_visible_body() {
                match destination {
                    Destination::FirstPageFooter => {
                        self.current_section_page.first_page_footer.push(paragraph)
                    }
                    Destination::EvenPageFooter => {
                        self.current_section_page.even_page_footer.push(paragraph)
                    }
                    _ => self.current_section_page.footer.push(paragraph),
                }
                self.upsert_current_section_settings();
            } else {
                match destination {
                    Destination::FirstPageFooter => self.document.first_page_footer.push(paragraph),
                    Destination::EvenPageFooter => self.document.even_page_footer.push(paragraph),
                    _ => self.document.footer.push(paragraph),
                }
            }
        }
        Ok(())
    }

    fn reserve_header_footer_paragraph_slot(&mut self, offset: usize) -> Result<(), ParseError> {
        self.reserve_header_footer_paragraph_slots(1, offset)
    }

    fn reserve_header_footer_paragraph_slots(
        &mut self,
        count: usize,
        offset: usize,
    ) -> Result<(), ParseError> {
        self.header_footer_paragraph_count = self
            .header_footer_paragraph_count
            .checked_add(count)
            .ok_or(ParseError::ResourceLimitExceeded {
                resource: "header/footer paragraphs".to_string(),
                offset,
            })?;
        if self.header_footer_paragraph_count > self.limits().max_header_footer_paragraphs {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "header/footer paragraphs".to_string(),
                offset,
            });
        }
        Ok(())
    }

    fn finish_footnote_paragraph(&mut self, offset: usize) -> Result<(), ParseError> {
        if !self.current_footnote_paragraph.runs.is_empty() {
            self.ensure_note_capacity(1, offset)?;
            let paragraph = std::mem::replace(
                &mut self.current_footnote_paragraph,
                Paragraph {
                    style: self.state.paragraph.clone(),
                    runs: Vec::new(),
                },
            );
            self.document.footnotes.push(paragraph);
            self.document
                .footnote_section_indices
                .push(self.current_section_index.max(1));
            self.document
                .footnote_block_indices
                .push(self.current_footnote_reference_block_index);
        }
        Ok(())
    }

    fn finish_endnote_paragraph(&mut self, offset: usize) -> Result<(), ParseError> {
        if !self.current_endnote_paragraph.runs.is_empty() {
            self.ensure_note_capacity(1, offset)?;
            let paragraph = std::mem::replace(
                &mut self.current_endnote_paragraph,
                Paragraph {
                    style: self.state.paragraph.clone(),
                    runs: Vec::new(),
                },
            );
            self.document.endnotes.push(paragraph);
            self.document
                .endnote_section_indices
                .push(self.current_section_index.max(1));
            self.document
                .endnote_placements
                .push(self.document.endnote_placement);
        }
        Ok(())
    }

    fn finish_note_separator_paragraph(&mut self, _offset: usize) -> Result<(), ParseError> {
        let destination = self.state.destination;
        let current = match destination {
            Destination::FootnoteSeparator => &mut self.current_footnote_separator_paragraph,
            Destination::FootnoteContinuationSeparator => {
                &mut self.current_footnote_continuation_separator_paragraph
            }
            Destination::EndnoteSeparator => &mut self.current_endnote_separator_paragraph,
            Destination::EndnoteContinuationSeparator => {
                &mut self.current_endnote_continuation_separator_paragraph
            }
            _ => return Ok(()),
        };
        if current.runs.is_empty() {
            return Ok(());
        }
        let paragraph = std::mem::replace(
            current,
            Paragraph {
                style: self.state.paragraph.clone(),
                runs: Vec::new(),
            },
        );
        match destination {
            Destination::FootnoteSeparator => self.document.footnote_separator = Some(paragraph),
            Destination::FootnoteContinuationSeparator => {
                self.document.footnote_continuation_separator = Some(paragraph)
            }
            Destination::EndnoteSeparator => self.document.endnote_separator = Some(paragraph),
            Destination::EndnoteContinuationSeparator => {
                self.document.endnote_continuation_separator = Some(paragraph)
            }
            _ => {}
        }
        Ok(())
    }

    fn ensure_note_capacity(&self, additional: usize, offset: usize) -> Result<(), ParseError> {
        let current = self
            .document
            .footnotes
            .len()
            .checked_add(self.document.endnotes.len())
            .ok_or(ParseError::ResourceLimitExceeded {
                resource: "notes".to_string(),
                offset,
            })?;
        let next = current
            .checked_add(additional)
            .ok_or(ParseError::ResourceLimitExceeded {
                resource: "notes".to_string(),
                offset,
            })?;
        if next > self.limits().max_notes {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "notes".to_string(),
                offset,
            });
        }
        Ok(())
    }

    fn finish_shape_text_paragraph(&mut self) {
        let Some(shape) = self.current_shape.as_mut() else {
            return;
        };
        if shape.current_text_paragraph.runs.is_empty() {
            return;
        }
        let paragraph = std::mem::replace(
            &mut shape.current_text_paragraph,
            Paragraph {
                style: self.state.paragraph.clone(),
                runs: Vec::new(),
            },
        );
        shape.text.push(paragraph);
        self.mark_shape_visual_result_rendered();
    }

    fn mark_shape_visual_result_rendered(&mut self) {
        if self.state.inside_shape {
            self.state.shape_visual_result_rendered = true;
        }
        if self.state.inside_shape_picture {
            self.state.shape_picture_rendered = true;
        }
    }

    fn mark_object_result_visible_content(&mut self) {
        if self.state.inside_object && self.state.object_result_seen {
            self.state.object_result_has_visible_content = true;
        }
    }

    fn mark_field_result_visible_content(&mut self) {
        if self.state.inside_field && self.state.field_result_seen {
            self.state.field_result_has_visible_content = true;
        }
    }

    fn push_placeholder(&mut self, text: String, offset: usize) -> Result<(), ParseError> {
        self.finish_paragraph(offset)?;
        self.mark_object_result_visible_content();
        self.mark_field_result_visible_content();
        self.push_document_block(Block::Placeholder(text), offset)?;
        Ok(())
    }

    fn push_placeholder_for_destination(
        &mut self,
        destination: Destination,
        text: String,
        offset: usize,
    ) -> Result<(), ParseError> {
        if self.state.inside_object
            && self.state.object_result_seen
            && text == "[Field removed: no passive result]"
        {
            return Ok(());
        }
        match destination {
            destination
                if is_header_destination(destination) || is_footer_destination(destination) =>
            {
                let previous_destination = self.state.destination;
                self.state.destination = destination;
                self.push_text(&text, offset)?;
                self.finish_current_paragraph_for_destination(offset)?;
                self.state.destination = previous_destination;
                Ok(())
            }
            Destination::Footnote | Destination::Endnote => {
                let previous_destination = self.state.destination;
                self.state.destination = destination;
                self.push_text(&text, offset)?;
                self.finish_current_paragraph_for_destination(offset)?;
                self.state.destination = previous_destination;
                Ok(())
            }
            _ => self.push_placeholder(text, offset),
        }
    }

    fn start_table_row(&mut self, offset: usize) -> Result<(), ParseError> {
        self.finish_paragraph(offset)?;
        if self.current_table.is_none() {
            let mut table = TableBuilder::default();
            table.preserve_authored_widths = self.preserve_authored_table_widths;
            self.current_table = Some(table);
        }
        self.current_table_row = Some(self.new_table_row_builder());
        Ok(())
    }

    fn new_table_row_builder(&self) -> TableRowBuilder {
        TableRowBuilder {
            cells: Vec::new(),
            cell_right_edges_twips: Vec::new(),
            cell_shading_color_indices: Vec::new(),
            cell_shading_basis_points: Vec::new(),
            cell_shading_patterns: Vec::new(),
            cell_paddings: Vec::new(),
            cell_borders: Vec::new(),
            cell_border_flags: Vec::new(),
            cell_preferred_widths_twips: Vec::new(),
            cell_no_wraps: Vec::new(),
            cell_fit_texts: Vec::new(),
            cell_spacings: Vec::new(),
            cell_text_directions: Vec::new(),
            cell_vertical_alignments: Vec::new(),
            cell_horizontal_merges: Vec::new(),
            cell_vertical_merges: Vec::new(),
            default_cell_shading_color_index: None,
            current_cell_shading_color_index: None,
            default_cell_shading_basis_points: 10_000,
            current_cell_shading_basis_points: 10_000,
            default_cell_shading_pattern: ShadingPattern::None,
            current_cell_shading_pattern: ShadingPattern::None,
            default_cell_padding: TableCellPadding::default(),
            current_cell_padding: TableCellPadding::default(),
            default_cell_spacing: TableCellSpacing::default(),
            current_cell_spacing: TableCellSpacing::default(),
            current_cell_borders: TableCellBorders::default(),
            current_cell_border_flags: TableCellBorderFlags::default(),
            current_cell_border_side: None,
            current_cell_preferred_width: PreferredTableWidth::default(),
            current_row_preferred_width: PreferredTableWidth::default(),
            current_cell_no_wrap: false,
            current_cell_fit_text: false,
            current_cell_text_direction: TableCellTextDirection::LeftToRightTopToBottom,
            row_borders: TableCellBorders::default(),
            row_inner_horizontal_border: TableCellBorder::default(),
            row_inner_vertical_border: TableCellBorder::default(),
            row_border_flags: TableCellBorderFlags::default(),
            current_row_border_side: None,
            current_cell_vertical_align: TableCellVerticalAlign::Top,
            current_cell_horizontal_merge: TableCellHorizontalMerge::None,
            current_cell_vertical_merge: TableCellVerticalMerge::None,
            height_twips: None,
            left_offset_twips: 0,
            horizontal_anchor_adjust_twips: 0,
            vertical_offset_twips: 0,
            vertical_anchor_adjust_twips: 0,
            vertical_position_alignment: FloatingTableVerticalPositionAlignment::Top,
            wrap_margins: TableRowWrapMargins::default(),
            cell_gap_twips: DEFAULT_TABLE_CELL_GAP_TWIPS,
            alignment: TableRowAlignment::Left,
            repeat_header: false,
            keep_together: false,
            right_to_left: false,
            current_cell_paragraphs: Vec::new(),
            current_cell_paragraph: Paragraph {
                style: self.state.paragraph.clone(),
                runs: Vec::new(),
            },
            cell_open: true,
        }
    }

    fn ensure_carried_table_row(&mut self) {
        if self.current_table_row.is_some() || self.current_table.is_none() {
            return;
        }

        let Some(template) = self.last_table_row_template.as_ref() else {
            return;
        };
        let mut row = template.clone();
        row.cells.clear();
        row.current_cell_paragraphs.clear();
        row.current_cell_paragraph = Paragraph {
            style: self.state.paragraph.clone(),
            runs: Vec::new(),
        };
        row.cell_open = true;
        self.current_table_row = Some(row);
    }

    fn table_row_template_from(
        row: &TableRowBuilder,
        paragraph_style: &ParagraphStyle,
    ) -> TableRowBuilder {
        let mut template = row.clone();
        template.cells.clear();
        template.current_cell_paragraphs.clear();
        template.current_cell_paragraph = Paragraph {
            style: paragraph_style.clone(),
            runs: Vec::new(),
        };
        template.cell_open = true;
        template
    }

    fn handle_nested_table_control(
        &mut self,
        control: &Control,
        offset: usize,
    ) -> Result<bool, ParseError> {
        if self.current_table_row.is_none() {
            return Ok(false);
        }

        match control.name.as_str() {
            "itap" if control.parameter.unwrap_or(1) > 1 => {
                self.set_table_nesting_level(control.parameter.unwrap_or(2).max(2), offset)?;
                return Ok(true);
            }
            "itap" if self.state.table_nesting_level > 1 => {
                self.set_table_nesting_level(control.parameter.unwrap_or(1).max(1), offset)?;
                return Ok(true);
            }
            "trowd" => {
                self.set_table_nesting_level(self.state.table_nesting_level.max(2), offset)?;
                return Ok(true);
            }
            _ => {}
        }

        if self.state.table_nesting_level <= 1 {
            return Ok(false);
        }

        match control.name.as_str() {
            "nestcell" | "cell" => {
                self.push_text("\t", offset)?;
                Ok(true)
            }
            "nestrow" | "row" => {
                self.push_text("\n", offset)?;
                self.state.table_nesting_level = 1;
                Ok(true)
            }
            name if is_nested_table_structural_control(name) => Ok(true),
            _ => Ok(false),
        }
    }

    fn set_table_nesting_level(&mut self, level: i32, offset: usize) -> Result<(), ParseError> {
        let level = level.max(1);
        let nesting_level =
            usize::try_from(level).map_err(|_| ParseError::ResourceLimitExceeded {
                resource: "table nesting".to_string(),
                offset,
            })?;
        if nesting_level > self.limits().max_table_nesting_level {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "table nesting".to_string(),
                offset,
            });
        }
        self.state.table_nesting_level = level;
        Ok(())
    }

    fn push_table_cell_boundary(
        &mut self,
        right_edge_twips: i32,
        offset: usize,
    ) -> Result<(), ParseError> {
        if right_edge_twips <= 0 || self.current_table_row.is_none() {
            return Ok(());
        }
        self.table_cell_boundary_count = self.table_cell_boundary_count.checked_add(1).ok_or(
            ParseError::ResourceLimitExceeded {
                resource: "table cell definitions".to_string(),
                offset,
            },
        )?;
        if self.table_cell_boundary_count > self.limits().max_table_cells {
            return Err(ParseError::ResourceLimitExceeded {
                resource: "table cell definitions".to_string(),
                offset,
            });
        }
        let page_content_width_twips = self.current_page_content_width_twips();
        let max_width_twips = self.limits().max_page_dimension_twips;
        if let Some(row) = self.current_table_row.as_mut() {
            let preferred_width_twips = normalized_preferred_table_width_twips(
                row.current_cell_preferred_width,
                page_content_width_twips,
                max_width_twips,
            );
            row.cell_right_edges_twips.push(right_edge_twips);
            row.cell_shading_color_indices
                .push(row.current_cell_shading_color_index);
            row.cell_shading_basis_points
                .push(row.current_cell_shading_basis_points);
            row.cell_shading_patterns
                .push(row.current_cell_shading_pattern);
            row.cell_paddings.push(row.current_cell_padding);
            row.cell_borders.push(row.current_cell_borders);
            row.cell_border_flags.push(row.current_cell_border_flags);
            row.cell_preferred_widths_twips.push(preferred_width_twips);
            row.cell_no_wraps.push(row.current_cell_no_wrap);
            row.cell_fit_texts.push(row.current_cell_fit_text);
            row.cell_spacings.push(row.current_cell_spacing);
            row.cell_text_directions
                .push(row.current_cell_text_direction);
            row.cell_vertical_alignments
                .push(row.current_cell_vertical_align);
            row.cell_horizontal_merges
                .push(row.current_cell_horizontal_merge);
            row.cell_vertical_merges
                .push(row.current_cell_vertical_merge);
            row.current_cell_shading_color_index = row.default_cell_shading_color_index;
            row.current_cell_shading_basis_points = row.default_cell_shading_basis_points;
            row.current_cell_shading_pattern = row.default_cell_shading_pattern;
            row.current_cell_padding = row.default_cell_padding;
            row.current_cell_borders = TableCellBorders::default();
            row.current_cell_border_flags = TableCellBorderFlags::default();
            row.current_cell_border_side = None;
            row.current_cell_preferred_width = PreferredTableWidth::default();
            row.current_cell_no_wrap = false;
            row.current_cell_fit_text = false;
            row.current_cell_spacing = row.default_cell_spacing;
            row.current_cell_text_direction = TableCellTextDirection::LeftToRightTopToBottom;
            row.current_cell_vertical_align = TableCellVerticalAlign::Top;
            row.current_cell_horizontal_merge = TableCellHorizontalMerge::None;
            row.current_cell_vertical_merge = TableCellVerticalMerge::None;
        }
        Ok(())
    }

