fn word_layout_compatibility_control_message(name: &str) -> Option<&'static str> {
    match name {
        "jexpand" | "jcompress" => {
            Some("Japanese text justification approximated by passive line layout")
        }
        "asianbrkrule" => {
            Some("Asian line-breaking rule approximated by passive Unicode line layout")
        }
        "sectexpand" | "sectspecifycl" | "sectspecifyl" => {
            Some("section text grid approximated by passive paragraph layout")
        }
        "lytexcttp" | "lytprtmet" | "noextrasprl" | "notcvasp" | "notvatxbx" | "expshrtn"
        | "useltbaln" | "htmautsp" | "wraptrsp" | "sprsspbf" | "sprsbsp" => {
            Some("Word typography compatibility option approximated by passive layout")
        }
        "vertdoc" => Some("vertical document layout approximated by passive horizontal layout"),
        _ => None,
    }
}

fn is_shape_layout_compatibility_control(name: &str) -> bool {
    match name {
        "dobxcolumn" | "dobxmargin" | "dobxpage" | "dobypara" | "dobymargin" | "dobypage"
        | "shpbxcolumn" | "shpbxmargin" | "shpbxpage" | "shpbypara" | "shpbymargin"
        | "shpbypage" | "dodhgt" | "shpz" | "shpfblwtxt" | "shpwr" | "shpwrk" | "shpfhdr"
        | "shplid" => true,
        _ => false,
    }
}

fn shape_layout_compatibility_control_message(
    name: &str,
    parameter: Option<i32>,
) -> Option<&'static str> {
    match name {
        "dobxcolumn" | "dobxmargin" | "dobxpage" | "dobypara" | "dobymargin" | "dobypage"
        | "shpbxcolumn" | "shpbxmargin" | "shpbxpage" | "shpbypara" | "shpbymargin"
        | "shpbypage" => None,
        "shpwr" if matches!(parameter.unwrap_or(1), 4 | 5) => {
            Some("shape contour wrapping approximated by passive bounding-box exclusion")
        }
        "shpwr" if !matches!(parameter.unwrap_or(1), 0..=5) => {
            Some("shape text wrapping approximated by passive shape layout")
        }
        "shpwrk" if !matches!(parameter.unwrap_or(0), 0..=3) => {
            Some("shape text wrapping approximated by passive shape layout")
        }
        "dodhgt" | "shpz" | "shpfblwtxt" | "shpwr" | "shpwrk" | "shpfhdr" | "shplid" => None,
        _ => None,
    }
}

fn table_layout_compatibility_control_message(name: &str) -> Option<&'static str> {
    match name {
        "trpaddfl" | "trpaddfr" | "trpaddft" | "trpaddfb" | "clpadfl" | "clpadfr" | "clpadft"
        | "clpadfb" | "trspdfl" | "trspdfr" | "trspdft" | "trspdfb" | "clspdfl" | "clspdfr"
        | "clspdft" | "clspdfb" => {
            Some("table padding and spacing units interpreted through bounded twip layout")
        }
        "tposx" | "tposnegx" | "tposxc" | "tposxi" | "tposxl" | "tposxr" | "tposy" | "tposnegy"
        | "tposyin" | "tposyout" => {
            Some("floating table positioning approximated by passive table flow")
        }
        _ => None,
    }
}

fn note_type_mode_from_parameter(value: i32) -> Option<NoteTypeMode> {
    match value {
        0 => Some(NoteTypeMode::FootnotesOnly),
        1 => Some(NoteTypeMode::EndnotesOnly),
        2 => Some(NoteTypeMode::FootnotesAndEndnotes),
        _ => None,
    }
}

fn footnote_placement_diagnostic_message(placement: FootnotePlacement) -> &'static str {
    match placement {
        FootnotePlacement::BeneathText => {
            "footnote placement rendered beneath document text as passive note layout"
        }
        FootnotePlacement::BottomOfPage => {
            "footnotes placed at passive page bottom without active note behavior"
        }
    }
}

fn endnote_placement_diagnostic_message(placement: EndnotePlacement) -> &'static str {
    match placement {
        EndnotePlacement::EndOfDocument => {
            "endnotes placed on passive final page without active note behavior"
        }
        EndnotePlacement::EndOfSection => {
            "endnotes placed at passive section boundary without active note behavior"
        }
        EndnotePlacement::AfterBody => "endnote placement rendered after body text",
    }
}

fn note_type_diagnostic_message(mode: NoteTypeMode) -> &'static str {
    match mode {
        NoteTypeMode::FootnotesOnly => "note type set to passive footnote-only interpretation",
        NoteTypeMode::EndnotesOnly => "note type set to passive endnote-only interpretation",
        NoteTypeMode::FootnotesAndEndnotes => {
            "note type set to passive footnote/endnote interpretation"
        }
    }
}

