fn metadata_nested_active_feature(name: &str) -> Option<&'static str> {
    match name {
        "object" | "objdata" | "objocx" | "objemb" | "objlink" | "objautlink" | "objupdate" => {
            Some("object payload in metadata")
        }
        name if is_embedded_package_destination(name) => {
            Some("embedded package payload in metadata")
        }
        "field" | "fldinst" => Some("field instruction in metadata"),
        "template" => Some("external template in metadata"),
        name if is_external_file_reference_destination(name) => {
            Some("external file reference in metadata")
        }
        name if is_macro_script_destination(name) => Some("macro/script payload in metadata"),
        "fontemb" | "fontfile" => Some("embedded font payload in metadata"),
        name if is_object_metadata_destination(name) => Some("object metadata in metadata"),
        name if is_mail_merge_destination(name) => Some("mail merge data source in metadata"),
        name if is_annotation_destination(name) => Some("annotation metadata in metadata"),
        "private" => Some("private metadata in metadata"),
        _ => None,
    }
}

fn is_macro_script_destination(name: &str) -> bool {
    matches!(
        name,
        "macro" | "macros" | "script" | "scripts" | "vba" | "vbaproject" | "activex"
    )
}

fn is_embedded_package_destination(name: &str) -> bool {
    matches!(name, "package" | "packager" | "embeddedpackage")
}

fn is_external_file_reference_destination(name: &str) -> bool {
    matches!(name, "filetbl" | "file" | "filepath" | "filename")
}

fn html_metadata_feature(name: &str) -> Option<&'static str> {
    match name {
        "htmltag" | "htmlbase" => Some("encapsulated HTML metadata"),
        _ => None,
    }
}

fn opaque_metadata_payload_feature(name: &str) -> Option<&'static str> {
    match name {
        "datastore" => Some("custom XML data store"),
        "colorschememapping" => Some("Office color scheme mapping"),
        "hlinkbase" => Some("hyperlink base"),
        name if html_metadata_feature(name).is_some() => html_metadata_feature(name),
        "themedata" => Some("Office theme data"),
        "xmlattrname" | "xmlattrns" | "xmlattrvalue" => Some("custom XML attribute metadata"),
        "xmlnstbl" => Some("custom XML namespace table"),
        "datafield" => Some("form field data payload"),
        "linkval" => Some("linked custom property value"),
        _ => None,
    }
}

fn custom_xml_markup_feature(name: &str) -> Option<&'static str> {
    match name {
        "xmlopen" | "xmlclose" => Some("custom XML markup"),
        _ => None,
    }
}

