fn destination_allows_visible_content(state: &ParserState) -> bool {
    !state.inside_metadata
        && !matches!(
            state.destination,
            Destination::Ignored | Destination::ObjectData | Destination::FieldInstruction
        )
}

fn destination_allows_field_result(state: &ParserState) -> bool {
    !state.inside_metadata
        && !matches!(
            state.destination,
            Destination::Ignored | Destination::ObjectData
        )
}

fn destination_allows_field_instruction(state: &ParserState) -> bool {
    !state.inside_metadata && state.destination != Destination::ObjectData
}

fn destination_allows_field_start(state: &ParserState) -> bool {
    !state.inside_metadata
        && matches!(
            state.destination,
            Destination::Body
                | Destination::ListText
                | Destination::Header
                | Destination::FirstPageHeader
                | Destination::EvenPageHeader
                | Destination::Footer
                | Destination::FirstPageFooter
                | Destination::EvenPageFooter
                | Destination::ShapeText
                | Destination::Footnote
                | Destination::Endnote
        )
}

fn destination_allows_bookmark_destination_start(
    state: &ParserState,
    stack: &[ParserState],
) -> bool {
    if state.inside_metadata {
        return false;
    }
    if state.destination == Destination::Ignored {
        return stack
            .last()
            .is_some_and(|parent| destination_allows_bookmark_destination_start(parent, &[]));
    }
    matches!(
        state.destination,
        Destination::Body
            | Destination::ListText
            | Destination::Header
            | Destination::FirstPageHeader
            | Destination::EvenPageHeader
            | Destination::Footer
            | Destination::FirstPageFooter
            | Destination::EvenPageFooter
            | Destination::ShapeText
            | Destination::Footnote
            | Destination::Endnote
    )
}

fn destination_allows_shape_picture_destination_start(
    state: &ParserState,
    stack: &[ParserState],
) -> bool {
    if state.inside_metadata {
        return false;
    }
    if state.destination == Destination::Ignored {
        return stack
            .last()
            .is_some_and(|parent| destination_allows_shape_picture_destination_start(parent, &[]));
    }
    destination_allows_visible_content(state)
}

fn destination_allows_object_result(state: &ParserState) -> bool {
    !state.inside_metadata && state.destination != Destination::Ignored
}

fn destination_allows_embedded_object_start(state: &ParserState) -> bool {
    !state.inside_metadata
        && matches!(
            state.destination,
            Destination::Body
                | Destination::Header
                | Destination::FirstPageHeader
                | Destination::EvenPageHeader
                | Destination::Footer
                | Destination::FirstPageFooter
                | Destination::EvenPageFooter
                | Destination::Shape
                | Destination::ShapeText
                | Destination::Footnote
                | Destination::Endnote
        )
}

fn destination_allows_safe_structural_content(state: &ParserState) -> bool {
    !state.inside_metadata
        && !matches!(
            state.destination,
            Destination::ObjectData | Destination::FieldInstruction
        )
}

fn destination_allows_structural_destination_start(
    state: &ParserState,
    stack: &[ParserState],
    control_follows_ignorable_destination_marker: bool,
) -> bool {
    if !destination_allows_safe_structural_content(state) {
        return false;
    }
    if state.destination != Destination::Ignored {
        return true;
    }
    control_follows_ignorable_destination_marker
        && stack.last().is_some_and(|parent| {
            !parent.inside_metadata
                && !matches!(
                    parent.destination,
                    Destination::Ignored | Destination::ObjectData | Destination::FieldInstruction
                )
        })
}

fn destination_allows_visible_old_style_list_marker(state: &ParserState) -> bool {
    !state.inside_metadata
        && matches!(
            state.destination,
            Destination::Body
                | Destination::ListText
                | Destination::Header
                | Destination::FirstPageHeader
                | Destination::EvenPageHeader
                | Destination::Footer
                | Destination::FirstPageFooter
                | Destination::EvenPageFooter
                | Destination::ShapeText
                | Destination::Footnote
                | Destination::Endnote
        )
}

fn is_header_destination(destination: Destination) -> bool {
    matches!(
        destination,
        Destination::Header | Destination::FirstPageHeader | Destination::EvenPageHeader
    )
}

fn is_footer_destination(destination: Destination) -> bool {
    matches!(
        destination,
        Destination::Footer | Destination::FirstPageFooter | Destination::EvenPageFooter
    )
}

fn is_note_separator_destination(destination: Destination) -> bool {
    matches!(
        destination,
        Destination::FootnoteSeparator
            | Destination::FootnoteContinuationSeparator
            | Destination::EndnoteSeparator
            | Destination::EndnoteContinuationSeparator
    )
}

fn append_field_instruction(
    target: &mut String,
    text: &str,
    limit: usize,
    offset: usize,
) -> Result<(), ParseError> {
    let new_len = target
        .chars()
        .count()
        .checked_add(text.chars().count())
        .ok_or(ParseError::OutputTextTooLarge(offset))?;
    if new_len > limit {
        return Err(ParseError::ResourceLimitExceeded {
            resource: "field instruction".to_string(),
            offset,
        });
    }
    target.push_str(text);
    Ok(())
}

