fn office_math_accent_is_passive_overline(text: &str) -> bool {
    let normalized = text.trim();
    matches!(
        normalized,
        "\u{00af}" | "\u{0305}" | "\u{033f}" | "\u{203e}"
    )
}

fn office_math_passive_text_accent(text: &str) -> Option<char> {
    let normalized = text.trim();
    match normalized {
        "^" | "\u{0302}" | "\u{02c6}" | "\u{2038}" => Some('^'),
        "~" | "\u{0303}" | "\u{02dc}" => Some('~'),
        "." | "\u{0307}" | "\u{02d9}" => Some('.'),
        "\u{00a8}" | "\u{0308}" => Some('"'),
        "\u{00b4}" | "\u{0301}" | "\u{02ca}" => Some('\''),
        "`" | "\u{0300}" | "\u{02cb}" => Some('`'),
        _ => None,
    }
}

fn passive_office_math_border_box() -> TableCellBorder {
    TableCellBorder {
        visible: true,
        width_twips: 10,
        spacing_twips: 20,
        color_index: None,
        style: BorderStyle::Single,
    }
}

fn office_math_group_char_kind(text: &str) -> OfficeMathGroupCharKind {
    match text.trim() {
        "\u{23b4}" | "\u{23dc}" | "\u{23de}" | "\u{23e0}" | "\u{fe35}" | "\u{fe37}"
        | "\u{fe3f}" => OfficeMathGroupCharKind::Over,
        "\u{23b5}" | "\u{23dd}" | "\u{23df}" | "\u{23e1}" | "\u{fe36}" | "\u{fe38}"
        | "\u{fe40}" => OfficeMathGroupCharKind::Under,
        _ => OfficeMathGroupCharKind::None,
    }
}

fn office_math_fraction_kind(text: &str) -> Option<OfficeMathFractionKind> {
    let normalized = text
        .trim()
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .flat_map(char::to_lowercase)
        .collect::<String>();
    match normalized.as_str() {
        "bar" => Some(OfficeMathFractionKind::Bar),
        "nobar" => Some(OfficeMathFractionKind::NoBar),
        "lin" | "linear" => Some(OfficeMathFractionKind::Linear),
        "skw" | "skewed" => Some(OfficeMathFractionKind::Skewed),
        _ => None,
    }
}

fn office_math_bar_position(text: &str) -> Option<OfficeMathBarPosition> {
    let normalized = text
        .trim()
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .flat_map(char::to_lowercase)
        .collect::<String>();
    match normalized.as_str() {
        "top" => Some(OfficeMathBarPosition::Top),
        "bot" | "bottom" => Some(OfficeMathBarPosition::Bottom),
        _ => None,
    }
}

fn apply_office_math_bar_position(style: &mut CharacterStyle, position: OfficeMathBarPosition) {
    match position {
        OfficeMathBarPosition::Top => {
            style.overline = true;
        }
        OfficeMathBarPosition::Bottom => {
            style.overline = false;
            style.underline = UnderlineStyle::Single;
        }
    }
}

fn office_math_nary_limit_location(text: &str) -> Option<OfficeMathNaryLimitLocation> {
    let normalized = text
        .trim()
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .flat_map(char::to_lowercase)
        .collect::<String>();
    match normalized.as_str() {
        "subsup" => Some(OfficeMathNaryLimitLocation::SubSup),
        "undovr" | "underover" => Some(OfficeMathNaryLimitLocation::UnderOver),
        _ => None,
    }
}

fn office_math_text_style(text: &str) -> Option<OfficeMathTextStyle> {
    let normalized = text
        .trim()
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .flat_map(char::to_lowercase)
        .collect::<String>();
    match normalized.as_str() {
        "p" | "plain" | "regular" => Some(OfficeMathTextStyle::Plain),
        "b" | "bold" => Some(OfficeMathTextStyle::Bold),
        "i" | "italic" => Some(OfficeMathTextStyle::Italic),
        "bi" | "bolditalic" | "bolditalics" => Some(OfficeMathTextStyle::BoldItalic),
        _ => None,
    }
}

fn apply_office_math_text_style(style: &mut CharacterStyle, math_style: OfficeMathTextStyle) {
    match math_style {
        OfficeMathTextStyle::Plain => {
            style.bold = false;
            style.italic = false;
        }
        OfficeMathTextStyle::Bold => {
            style.bold = true;
            style.italic = false;
        }
        OfficeMathTextStyle::Italic => {
            style.bold = false;
            style.italic = true;
        }
        OfficeMathTextStyle::BoldItalic => {
            style.bold = true;
            style.italic = true;
        }
    }
}

fn office_math_single_separator(text: &str) -> Option<String> {
    let mut chars = text.trim().chars();
    let ch = chars.next()?;
    if chars.next().is_none() && !ch.is_control() {
        Some(ch.to_string())
    } else {
        None
    }
}

