fn parse_shape_property_i64(value: &str) -> Option<i64> {
    value.trim().parse::<i64>().ok()
}

fn parse_shape_rotation_units(value: &str) -> Option<i32> {
    const OFFICE_ROTATION_UNITS_PER_DEGREE: i64 = 60_000;
    const FULL_ROTATION_UNITS: i64 = 360 * OFFICE_ROTATION_UNITS_PER_DEGREE;
    let value = parse_shape_property_i64(value)?;
    let normalized = value.rem_euclid(FULL_ROTATION_UNITS);
    i32::try_from(normalized).ok()
}

fn parse_shape_property_emu_twips(value: &str) -> Option<i64> {
    let emu = parse_shape_property_i64(value)?;
    Some(((emu.max(0).saturating_add(317)) / 635).min(i32::MAX as i64))
}

fn parse_office_shape_color(value: &str) -> Option<Color> {
    let value = u32::try_from(parse_shape_property_i64(value)?).ok()?;
    if value > 0x00ff_ffff {
        return None;
    }
    Some(Color {
        red: (value & 0xff) as u8,
        green: ((value >> 8) & 0xff) as u8,
        blue: ((value >> 16) & 0xff) as u8,
    })
}

fn parse_shape_line_dashing_property(value: &str) -> Option<BorderStyle> {
    let normalized = value
        .trim()
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .flat_map(char::to_lowercase)
        .collect::<String>();
    match normalized.as_str() {
        "0" | "1" | "solid" | "single" => Some(BorderStyle::Single),
        "2" | "3" | "dot" | "sysdot" | "squaredot" | "rounddot" | "linestyle2" | "linestyle3" => {
            Some(BorderStyle::Dotted)
        }
        "4" | "5" | "6" | "7" | "8" | "9" | "10" | "12" | "dash" | "sysdash" | "lgdash"
        | "longdash" | "dashdot" | "lgdashdot" | "dashdotdot" | "lgdashdotdot" | "longdashdot"
        | "longdashdotdot" | "sysdashdot" => Some(BorderStyle::Dashed),
        _ => None,
    }
}

fn parse_shape_line_style_property(value: &str) -> Option<(BorderStyle, bool)> {
    let normalized = value
        .trim()
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .flat_map(char::to_lowercase)
        .collect::<String>();
    match normalized.as_str() {
        "0" | "1" | "single" | "msolinesingle" => Some((BorderStyle::Single, false)),
        "2" | "3" | "4" | "thinthin" | "thinthick" | "thickthin" | "msolinethinthin"
        | "msolinethinthick" | "msolinethickthin" => Some((BorderStyle::Double, false)),
        "5" | "thickbetweenthin" | "msolinethickbetweenthin" => Some((BorderStyle::Double, true)),
        _ => None,
    }
}

#[derive(Debug, Copy, Clone, PartialEq, Eq)]
struct ShapeTextAnchor {
    vertical: StaticShapeTextVerticalAnchor,
    center_horizontal: bool,
}

fn parse_shape_text_anchor_property(value: &str) -> Option<ShapeTextAnchor> {
    let normalized = value
        .trim()
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .flat_map(char::to_lowercase)
        .collect::<String>();
    match normalized.as_str() {
        "0" | "top" | "t" => Some(ShapeTextAnchor {
            vertical: StaticShapeTextVerticalAnchor::Top,
            center_horizontal: false,
        }),
        "1" | "middle" | "center" | "ctr" | "mid" => Some(ShapeTextAnchor {
            vertical: StaticShapeTextVerticalAnchor::Middle,
            center_horizontal: false,
        }),
        "2" | "bottom" | "b" => Some(ShapeTextAnchor {
            vertical: StaticShapeTextVerticalAnchor::Bottom,
            center_horizontal: false,
        }),
        "3" | "topcentered" | "centertop" => Some(ShapeTextAnchor {
            vertical: StaticShapeTextVerticalAnchor::Top,
            center_horizontal: true,
        }),
        "4" | "middlecentered" | "centermiddle" | "centercentered" => Some(ShapeTextAnchor {
            vertical: StaticShapeTextVerticalAnchor::Middle,
            center_horizontal: true,
        }),
        "5" | "bottomcentered" | "centerbottom" => Some(ShapeTextAnchor {
            vertical: StaticShapeTextVerticalAnchor::Bottom,
            center_horizontal: true,
        }),
        "6" | "baseline" => Some(ShapeTextAnchor {
            vertical: StaticShapeTextVerticalAnchor::Top,
            center_horizontal: false,
        }),
        "7" | "bottombaseline" => Some(ShapeTextAnchor {
            vertical: StaticShapeTextVerticalAnchor::Bottom,
            center_horizontal: false,
        }),
        "8" | "centerbaseline" => Some(ShapeTextAnchor {
            vertical: StaticShapeTextVerticalAnchor::Top,
            center_horizontal: true,
        }),
        "9" | "centerbottombaseline" => Some(ShapeTextAnchor {
            vertical: StaticShapeTextVerticalAnchor::Bottom,
            center_horizontal: true,
        }),
        _ => None,
    }
}

fn parse_shape_arrowhead_property(value: &str) -> Option<StaticShapeArrowhead> {
    let normalized = value
        .trim()
        .chars()
        .filter(|ch| ch.is_ascii_alphanumeric())
        .flat_map(char::to_lowercase)
        .collect::<String>();
    match normalized.as_str() {
        "0" | "1" | "none" | "noarrow" => Some(StaticShapeArrowhead::None),
        "3" | "open" | "arrow" => Some(StaticShapeArrowhead::Open),
        "2" | "triangle" => Some(StaticShapeArrowhead::Triangle),
        _ => None,
    }
}

fn merge_child_field_instruction(
    target: &mut String,
    child: &str,
    limit: usize,
    offset: usize,
) -> Result<(), ParseError> {
    let addition = child.strip_prefix(target.as_str()).unwrap_or(child);
    append_field_instruction(target, addition, limit, offset)
}

fn merge_child_form_default_text(
    target: &mut String,
    child: &str,
    limit: usize,
    offset: usize,
) -> Result<(), ParseError> {
    let addition = child.strip_prefix(target.as_str()).unwrap_or(child);
    let new_len = target
        .chars()
        .count()
        .checked_add(addition.chars().count())
        .ok_or(ParseError::OutputTextTooLarge(offset))?;
    if new_len > limit {
        return Err(ParseError::ResourceLimitExceeded {
            resource: "form default text".to_string(),
            offset,
        });
    }
    target.push_str(addition);
    Ok(())
}

fn merge_child_form_dropdown_entry_text(
    target: &mut String,
    child: &str,
    limit: usize,
    offset: usize,
) -> Result<(), ParseError> {
    let addition = child.strip_prefix(target.as_str()).unwrap_or(child);
    let new_len = target
        .chars()
        .count()
        .checked_add(addition.chars().count())
        .ok_or(ParseError::OutputTextTooLarge(offset))?;
    if new_len > limit {
        return Err(ParseError::ResourceLimitExceeded {
            resource: "form dropdown entry text".to_string(),
            offset,
        });
    }
    target.push_str(addition);
    Ok(())
}

fn push_form_dropdown_entry(
    entries: &mut Vec<String>,
    entry: &str,
    limit: usize,
    offset: usize,
) -> Result<(), ParseError> {
    let entry = entry.trim_end();
    if entry.is_empty() || entry.chars().any(|ch| ch.is_control()) {
        return Ok(());
    }
    if entries.len() >= limit {
        return Err(ParseError::ResourceLimitExceeded {
            resource: "form dropdown entries".to_string(),
            offset,
        });
    }
    entries.push(entry.to_string());
    Ok(())
}

fn merge_child_form_dropdown_entries(
    target: &mut Vec<String>,
    child: &[String],
    limit: usize,
    offset: usize,
) -> Result<(), ParseError> {
    let additions = if child.len() >= target.len() && child.starts_with(target.as_slice()) {
        &child[target.len()..]
    } else {
        child
    };
    for entry in additions {
        push_form_dropdown_entry(target, entry, limit, offset)?;
    }
    Ok(())
}

