#[derive(Debug, Copy, Clone, PartialEq, Eq)]
enum PassiveSourceRasterTransferMode {
    Copy,
    Invert,
    Mask(Color),
    Solid(Color),
    SourceIgnoring {
        raster_op: u32,
        selected_fill_color: Option<Color>,
        blank_destination: bool,
    },
    SameBoundsBackdropAndIfSolidSource,
    SameBoundsBackdropNorIfSolidSource,
    SameBoundsBackdropOrIfSolidSource,
    SameBoundsBackdropOrNotSourceIfSolidSource,
    SameBoundsBackdropOrPatternOrNotSourceIfSolidSource {
        pattern: Color,
        blank_destination: bool,
    },
    SameBoundsBackdropSourceAndNotDestIfSolidSource,
    SameBoundsBackdropXorIfSolidSource,
}

enum PassiveSourceRasterTransfer {
    Image(ParsedVectorRasterImage),
    Solid(Color),
    SameBoundsBackdropAnd(Color),
    SameBoundsBackdropNor(Color),
    SameBoundsBackdropOr(Color),
    SameBoundsBackdropSourceAndNotDest(Color),
    SameBoundsBackdropXor(Color),
    Noop,
}

enum PassiveSourceRasterCommand {
    Draw(StaticImageVectorCommand),
    DrawMany(Vec<StaticImageVectorCommand>),
    ReduceSameBoundsBackdrop {
        bounds: (f32, f32, f32, f32),
        raster_op: u32,
        selected_fill_color: Option<Color>,
    },
    Noop,
}

fn source_ignoring_passive_source_raster_command(
    bounds: (f32, f32, f32, f32),
    raster_op: u32,
    selected_fill_color: Option<Color>,
    blank_destination: bool,
) -> Option<PassiveSourceRasterCommand> {
    match raster_op {
        WMF_NOTPATCOPY_RASTER_OP => {
            let fill_color = inverted_color(selected_fill_color?);
            Some(passive_source_raster_command(
                bounds.0,
                bounds.1,
                bounds.2,
                bounds.3,
                PassiveSourceRasterTransfer::Solid(fill_color),
            ))
        }
        WMF_PATINVERT_RASTER_OP if selected_fill_color == Some(Color::default()) => {
            Some(PassiveSourceRasterCommand::Noop)
        }
        WMF_PATINVERT_RASTER_OP if blank_destination => {
            let fill_color = inverted_color(selected_fill_color?);
            Some(passive_source_raster_command(
                bounds.0,
                bounds.1,
                bounds.2,
                bounds.3,
                PassiveSourceRasterTransfer::Solid(fill_color),
            ))
        }
        WMF_PATINVERT_RASTER_OP => Some(PassiveSourceRasterCommand::ReduceSameBoundsBackdrop {
            bounds,
            raster_op,
            selected_fill_color,
        }),
        _ => None,
    }
}

#[derive(Debug, Copy, Clone)]
struct DibColorMasks {
    red: u32,
    green: u32,
    blue: u32,
    alpha: Option<u32>,
}

impl DibColorMasks {
    fn are_supported(self) -> bool {
        if self.red == 0
            || self.green == 0
            || self.blue == 0
            || self.red & self.green != 0
            || self.red & self.blue != 0
            || self.green & self.blue != 0
        {
            return false;
        }
        let Some(alpha) = self.alpha else {
            return true;
        };
        alpha != 0 && self.red & alpha == 0 && self.green & alpha == 0 && self.blue & alpha == 0
    }
}

