        let mut invert = emf_invertrgn_record(&[]);
        invert.extend_from_slice(b"EMPTY-EMF-INVERTRGN /OpenAction");
        invert.resize(invert.len().next_multiple_of(4), 0);
        let invert_len = invert.len() as u32;
